class Solution:
    def minDays(self, n: int) -> int:
        days = 0
        while n > 1:
            if n % 2 == 0 and n % 3 != 0:
                n = n // 2
            elif n % 3 == 0:
                n = n // 3
            else:
                n = n - 1
            days += 1
        return days + 1
```

